SELECT mo.id, mo.order_no, mo.user_id, mo.pet_id, mo.doctor_id, mo.department_id, mo.appointment_time, mo.symptom, mo.price, mo.status, mo.remark, mo.create_time, mo.update_time, pet.name AS pet_name, u.username AS owner_name, doc.name AS doctor_name, dept.name AS department_name FROM medical_order mo LEFT JOIN pet ON mo.pet_id = pet.id LEFT JOIN user u ON mo.user_id = u.id LEFT JOIN doctor doc ON mo.doctor_id = doc.id LEFT JOIN department dept ON mo.department_id = dept.id
AND (mo.order_no LIKE CONCAT('%',#{keyword},'%') OR pet.name LIKE CONCAT('%',#{keyword},'%') OR u.username LIKE CONCAT('%',#{keyword},'%') OR doc.name LIKE CONCAT('%',#{keyword},'%') OR dept.name LIKE CONCAT('%',#{keyword},'%'))
AND mo.status = #{status}
ORDER BY mo.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM medical_order mo LEFT JOIN pet ON mo.pet_id = pet.id LEFT JOIN user u ON mo.user_id = u.id LEFT JOIN doctor doc ON mo.doctor_id = doc.id LEFT JOIN department dept ON mo.department_id = dept.id
AND (mo.order_no LIKE CONCAT('%',#{keyword},'%') OR pet.name LIKE CONCAT('%',#{keyword},'%') OR u.username LIKE CONCAT('%',#{keyword},'%') OR doc.name LIKE CONCAT('%',#{keyword},'%') OR dept.name LIKE CONCAT('%',#{keyword},'%'))
AND mo.status = #{status}

