order_no = #{orderNo}, user_id = #{userId}, pet_id = #{petId}, doctor_id = #{doctorId}, department_id = #{departmentId}, appointment_time = #{appointmentTime}, symptom = #{symptom}, price = #{price}, status = #{status}, remark = #{remark},
WHERE id = #{id}
